import{_ as o,W as s,X as _,$ as l,Y as e,Z as t,a0 as a,C as c}from"./framework-a9f5de78.js";const i="/assets/images/LBS_20th.png",r={},d=e("p",null,"2023年4月16日～4月18日，我前往了合肥，并在4月18日当日往返南京。 顺便在此再祝卢宝20岁生日快乐。",-1),p=e("figure",null,[e("img",{src:i,alt:"LBS 20岁生日会（",tabindex:"0",loading:"lazy"}),e("figcaption",null,"LBS 20岁生日会（")],-1),u=e("p",null,"合肥虽然玩的地方不比其他地方多，但是合肥可以会面的同学是最多的。",-1),m=e("p",null,"好久没见过像合肥这样多的路边摊了，上次见到这么多路边摊还是在丽水的西城。合肥很多地方都会有一长串摊子，大商场门口会有，网红景点（比如合柴1972）会有，甚至USTC门口也会有（相比之下摆大就只有一个需要躲躲藏藏的杰哥）。",-1),h=e("p",null,"早就听闻合肥最好玩的地方是合肥南站，而南京也被戏称为安徽的省会，所以就顺路去了趟南京。",-1),f=e("p",null,"在南京的旅游景点里，能看到很多类似的东西，在同一条街上你能看到十几家卖竹筒奶茶的。也能看到一些别的地方不太好看到的东西，比如以科举为主题的博物馆，又比如鼓吹元宇宙，将佛教与科技交融的大报恩寺遗址景区。",-1),g=e("p",null,"但是令我不得不吐槽的是南京的坑人套路，在南京我起码看到了七八次这样的地方！",-1),B=e("p",null,"果然免费的才是最贵的，这种套路太深了！",-1);function N(x,v){const n=c("Badge");return s(),_("div",null,[d,p,l(" more "),u,m,h,f,g,e("p",null,[t("她们一般会在景点出没，并声称会送免费赠品，等你走到附近（大部分是专门设置在出口位置的，很难避开），她们会收走你的券，然后让你挑选刻有你的名字的珠子。挑选完珠子后反问赠品在哪，她们会说，珠子一个3元，买完珠子就可以送你了。一个3元，乍一听还行，买就买吧。但是买完之后，她们会领你去一个桌子，然后就把你的珠子变成简陋的手链或者挂饰，在其中会加上价格一二十的小连接件，最后收你一百"),a(n,{text:"太坑了！",type:"danger"}),t("。")]),B])}const S=o(r,[["render",N],["__file","TravelNotes_Hefei_Nanjing.html.vue"]]);export{S as default};
